function getLeadPayload(item) {
  // Webhook node outputs fields inside item.json.body.
  // CSV parser outputs fields directly in item.json.
  if (item.json.body && typeof item.json.body === 'object') {
    return item.json.body;
  }

  return item.json;
}

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

return items.map((item, index) => {
  const lead = getLeadPayload(item);

  return {
    json: {
      intake_id: `${Date.now()}_${index}`,
      intake_received_at: new Date().toISOString(),

      timestamp: clean(lead.timestamp),
      first_name: clean(lead.first_name),
      last_name: clean(lead.last_name),
      company_name: clean(lead.company_name),
      email: clean(lead.email),
      phone: clean(lead.phone),
      country: clean(lead.country),
      interest: clean(lead.interest),
      message: clean(lead.message),
      source: clean(lead.source || 'unknown'),
      language: clean(lead.language || 'unknown'),

      raw_payload: lead,
      intake_status: 'received'
    }
  };
});

const EXPECTED_FIELDS = [
  'timestamp',
  'first_name',
  'last_name',
  'company_name',
  'email',
  'phone',
  'country',
  'interest',
  'message',
  'source',
  'language'
];

const GENERIC_EMAIL_DOMAINS = [
  'gmail.com',
  'googlemail.com',
  'outlook.com',
  'hotmail.com',
  'yahoo.com',
  'icloud.com',
  'aol.com',
  'proton.me',
  'protonmail.com',
  'gmx.com',
  'gmx.de',
  'web.de',
  'live.com',
  'msn.com'
];

const LEGAL_SUFFIXES = [
  'sdn',
  'bhd',
  'berhad',
  'enterprise',
  'holdings',
  'group',
  'gmbh',
  'ag',
  'se',
  'ltd',
  'llc',
  'inc',
  'corp',
  'corporation',
  'srl',
  'bv',
  'nv',
  'spa',
  'sa',
  'oy',
  'as',
  'ab'
];

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function lower(value) {
  return clean(value).toLowerCase();
}

function normalizeUnicode(value) {
  return clean(value)
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/ä/g, 'ae')
    .replace(/ö/g, 'oe')
    .replace(/ü/g, 'ue')
    .replace(/Ä/g, 'Ae')
    .replace(/Ö/g, 'Oe')
    .replace(/Ü/g, 'Ue')
    .replace(/ß/g, 'ss');
}

function normalizeEmail(value) {
  return lower(value);
}

function extractEmailDomain(email) {
  const normalizedEmail = normalizeEmail(email);

  if (!normalizedEmail || !normalizedEmail.includes('@')) return '';

  const parts = normalizedEmail.split('@');

  if (parts.length !== 2) return '';

  return parts[1] || '';
}

function normalizeDomain(value) {
  let domain = lower(value);

  domain = domain
    .replace(/^https?:\/\//, '')
    .replace(/^www\./, '')
    .split('/')[0]
    .split('?')[0]
    .split('#')[0]
    .trim();

  return domain;
}

function looksLikeDomain(value) {
  const text = normalizeDomain(value);

  return /^[a-z0-9.-]+\.[a-z]{2,}$/.test(text);
}

function tokenize(value) {
  return clean(value)
    .split(/\s+/)
    .map(part => part.trim())
    .filter(Boolean);
}

function hasLegalSuffix(value) {
  const words = normalizeUnicode(value)
    .toLowerCase()
    .replace(/[.,]/g, '')
    .split(/\s+/)
    .filter(Boolean);

  return words.some(word => LEGAL_SUFFIXES.includes(word));
}

function stripLegalSuffixes(value) {
  const suffixPattern = new RegExp(`\\b(${LEGAL_SUFFIXES.join('|')})\\b\\.?`, 'gi');

  return normalizeUnicode(value)
    .replace(suffixPattern, '')
    .replace(/[.,]/g, ' ')
    .replace(/[^a-zA-Z0-9&\- ]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeCompanyName(value) {
  return stripLegalSuffixes(value)
    .toLowerCase()
    .replace(/&/g, ' and ')
    .replace(/[^a-z0-9]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function looksLikePersonName(value) {
  const text = clean(value);
  const words = tokenize(text);

  if (!text) return false;
  if (looksLikeDomain(text)) return false;
  if (hasLegalSuffix(text)) return false;
  if (words.length < 2 || words.length > 4) return false;

  return words.every(word => {
    return /^[A-ZÀ-ÖØ-Þ][a-zà-öø-ÿ'’-]+$/.test(word);
  });
}

function looksStructurallyLikeCompany(value) {
  const text = clean(value);
  const words = tokenize(text);

  if (!text) return false;
  if (looksLikeDomain(text)) return true;
  if (hasLegalSuffix(text)) return true;

  const hasBusinessPunctuation = /[&+]/.test(text);

  const hasMultiWordCapitalizedName =
    words.length >= 2 &&
    words.some(word => /^[A-ZÀ-ÖØ-Þ]/.test(word)) &&
    !looksLikePersonName(text);

  return hasBusinessPunctuation || hasMultiWordCapitalizedName;
}

function normalizeForComparison(value) {
  return normalizeUnicode(value)
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function emailLocalPartLooksLikeName(email, nameValue) {
  const normalizedEmail = normalizeEmail(email);

  if (!normalizedEmail.includes('@')) return false;

  const localPart = normalizedEmail
    .split('@')[0]
    .replace(/[^a-z0-9]+/gi, ' ')
    .toLowerCase()
    .trim();

  const normalizedName = normalizeForComparison(nameValue);

  if (!localPart || !normalizedName) return false;

  const nameParts = normalizedName
    .split(/\s+/)
    .filter(Boolean);

  return nameParts.length >= 2 && nameParts.every(part => localPart.includes(part));
}

function detectLikelySwappedFields(lead) {
  const firstName = clean(lead.first_name);
  const lastName = clean(lead.last_name);
  const companyName = clean(lead.company_name);
  const email = clean(lead.email);

  if (!firstName || !companyName) return false;

  const companyFieldLooksLikePerson =
    looksLikePersonName(companyName) ||
    emailLocalPartLooksLikeName(email, companyName);

  const firstFieldLooksCompany =
    looksStructurallyLikeCompany(firstName) ||
    (
      tokenize(firstName).length >= 2 &&
      !emailLocalPartLooksLikeName(email, firstName) &&
      !hasLegalSuffix(companyName)
    );

  const lastNameMissing = !lastName;

  return firstFieldLooksCompany && companyFieldLooksLikePerson && lastNameMissing;
}

function splitPersonName(fullName) {
  const parts = clean(fullName).split(/\s+/).filter(Boolean);

  if (parts.length === 0) {
    return {
      first_name: '',
      last_name: '',
      full_name: ''
    };
  }

  if (parts.length === 1) {
    return {
      first_name: parts[0],
      last_name: '',
      full_name: parts[0]
    };
  }

  return {
    first_name: parts[0],
    last_name: parts.slice(1).join(' '),
    full_name: parts.join(' ')
  };
}

function detectLanguageFromMessage(message) {
  const text = lower(message);

  if (!text) return 'unknown';

  const malayStopWords = [
    'kami',
    'sedang',
    'mencari',
    'rakan',
    'kongsi',
    'untuk',
    'dan',
    'dengan',
    'sistem',
    'tenaga',
    'solar',
    'bangunan',
    'majlis',
    'menilai',
    'pilihan',
    'projek',
    'selamat',
    'pagi',
    'bateri',
    'integrasi',
    'grid'
  ];

  const englishStopWords = [
    'we',
    'and',
    'the',
    'for',
    'with',
    'please',
    'looking',
    'interested',
    'project',
    'contact',
    'our',
    'your',
    'would',
    'like',
    'send',
    'schedule',
    'call',
    'are',
    'is',
    'to',
    'in',
    'of'
  ];

  let msScore = 0;
  let enScore = 0;

  const words = text
    .replace(/[^a-z ]/gi, ' ')
    .split(/\s+/)
    .filter(Boolean);

  for (const word of words) {
    if (malayStopWords.includes(word)) msScore++;
    if (englishStopWords.includes(word)) enScore++;
  }

  if (msScore > enScore && msScore >= 2) return 'ms';
  if (enScore > msScore && enScore >= 2) return 'en';

  return 'unknown';
}

function getMissingFields(lead) {
  return EXPECTED_FIELDS.filter(field => {
    return lead[field] === undefined ||
      lead[field] === null ||
      String(lead[field]).trim() === '';
  });
}

function isMostlyEmptyRecord(lead) {
  const identityFields = [
    'first_name',
    'last_name',
    'company_name',
    'email',
    'phone',
    'country',
    'interest',
    'message'
  ];

  const presentIdentityFields = identityFields.filter(field => {
    return lead[field] !== undefined &&
      lead[field] !== null &&
      String(lead[field]).trim() !== '';
  });

  return presentIdentityFields.length === 0;
}

function calculateConfidence({
  email,
  isGenericEmailDomain,
  companyName,
  missingFields,
  warnings,
  emptyRecord
}) {
  if (emptyRecord) return 'low';

  const hasUsableEmail = Boolean(email) && !isGenericEmailDomain;
  const hasCompanyName = Boolean(companyName);

  const hasMajorWarnings = warnings.some(warning =>
    [
      'empty_record',
      'missing_company_name',
      'missing_email',
      'generic_email_domain',
      'possible_swapped_person_and_company_fields'
    ].includes(warning)
  );

  if (hasUsableEmail && hasCompanyName && !hasMajorWarnings) {
    return 'high';
  }

  if ((hasUsableEmail || hasCompanyName) && missingFields.length < EXPECTED_FIELDS.length - 2) {
    return 'medium';
  }

  return 'low';
}

return items.map((item) => {
  const lead = item.json || {};

  const missingFields = getMissingFields(lead);
  const emptyRecord = isMostlyEmptyRecord(lead);

  const email = normalizeEmail(lead.email);
  const emailDomain = extractEmailDomain(email);

  const originalCompanyName = clean(lead.company_name);
  const originalCompanyNameLooksDomain = looksLikeDomain(originalCompanyName);

  const isGenericEmailDomain = GENERIC_EMAIL_DOMAINS.includes(emailDomain);
  const usableEmailDomain = emailDomain && !isGenericEmailDomain ? emailDomain : '';

  const suppliedLanguage = lower(lead.language);
  const detectedLanguage = suppliedLanguage || detectLanguageFromMessage(lead.message);

  const likelySwappedFields = detectLikelySwappedFields(lead);

  let correctedFirstName = clean(lead.first_name);
  let correctedLastName = clean(lead.last_name);
  let correctedCompanyName = originalCompanyName;

  if (likelySwappedFields) {
    const correctedPerson = splitPersonName(originalCompanyName);

    correctedFirstName = correctedPerson.first_name;
    correctedLastName = correctedPerson.last_name;
    correctedCompanyName = clean(lead.first_name);
  }

  const correctedCompanyNameLooksDomain = looksLikeDomain(correctedCompanyName);

  const domainFromCompanyField = correctedCompanyNameLooksDomain
    ? normalizeDomain(correctedCompanyName)
    : '';

  const inferredCompanyDomain =
    domainFromCompanyField ||
    usableEmailDomain ||
    '';

  const extractionWarnings = [];

  if (emptyRecord) {
    extractionWarnings.push('empty_record');
  }

  if (likelySwappedFields) {
    extractionWarnings.push('possible_swapped_person_and_company_fields');
    extractionWarnings.push('fields_corrected_from_swap');
  }

  if (originalCompanyNameLooksDomain || correctedCompanyNameLooksDomain) {
    extractionWarnings.push('company_name_field_contains_domain');
  }

  if (isGenericEmailDomain) {
    extractionWarnings.push('generic_email_domain');
  }

  if (!correctedCompanyName) {
    extractionWarnings.push('missing_company_name');
  }

  if (!email) {
    extractionWarnings.push('missing_email');
  }

  if (suppliedLanguage === '' && detectedLanguage !== 'unknown') {
    extractionWarnings.push('language_detected_from_message');
  }

  if (suppliedLanguage === '' && detectedLanguage === 'unknown') {
    extractionWarnings.push('language_unknown');
  }

  const confidence = calculateConfidence({
    email,
    isGenericEmailDomain,
    companyName: correctedCompanyName,
    missingFields,
    warnings: extractionWarnings,
    emptyRecord
  });

  return {
    json: {
      ...lead,

      extracted: {
        person: {
          first_name: correctedFirstName,
          last_name: correctedLastName,
          full_name: `${correctedFirstName} ${correctedLastName}`.trim(),
          email,
          phone: clean(lead.phone)
        },

        company: {
          raw_name: correctedCompanyName,
          normalized_name: normalizeCompanyName(correctedCompanyName),
          domain_from_company_field: domainFromCompanyField,
          email_domain: emailDomain,
          usable_email_domain: usableEmailDomain,
          inferred_domain: inferredCompanyDomain,
          is_generic_email_domain: isGenericEmailDomain
        },

        lead_context: {
          timestamp: clean(lead.timestamp),
          country: clean(lead.country),
          interest: clean(lead.interest),
          message: clean(lead.message),
          source: clean(lead.source),
          language: suppliedLanguage || detectedLanguage,
          detected_language: detectedLanguage
        },

        extraction: {
          status: 'extracted',
          method: 'rule_based_generic_v3',
          confidence,
          missing_fields: missingFields,
          warnings: extractionWarnings,
          likely_swapped_fields: likelySwappedFields,
          empty_record: emptyRecord
        }
      }
    }
  };
});

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function isValidEmail(email) {
  const value = clean(email).toLowerCase();

  if (!value) return false;

  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
}

function hasLikelyEmailTypo(emailDomain) {
  const domain = clean(emailDomain).toLowerCase();

  const typoDomains = {
    'gmali.com': 'gmail.com',
    'gmai.com': 'gmail.com',
    'gmail.co': 'gmail.com',
    'hotmial.com': 'hotmail.com',
    'outlok.com': 'outlook.com',
    'yaho.com': 'yahoo.com'
  };

  return typoDomains[domain] || '';
}

function isValidTimestamp(timestamp) {
  const value = clean(timestamp);

  if (!value) return false;

  const parsed = Date.parse(value);

  return !Number.isNaN(parsed);
}

function isRecordUsableForHumanReview(extracted) {
  const email = clean(extracted?.person?.email);
  const companyName = clean(extracted?.company?.raw_name);
  const message = clean(extracted?.lead_context?.message);
  const interest = clean(extracted?.lead_context?.interest);

  return Boolean(email || companyName || message || interest);
}

return items.map((item) => {
  const lead = item.json;
  const extracted = lead.extracted || {};

  const validationErrors = [];
  const validationWarnings = [];
  const reviewReasons = [];

  const email = clean(extracted?.person?.email);
  const emailDomain = clean(extracted?.company?.email_domain);
  const companyName = clean(extracted?.company?.raw_name);
  const inferredDomain = clean(extracted?.company?.inferred_domain);
  const timestamp = clean(extracted?.lead_context?.timestamp);
  const country = clean(extracted?.lead_context?.country);
  const message = clean(extracted?.lead_context?.message);
  const confidence = clean(extracted?.extraction?.confidence);
  const extractionWarnings = extracted?.extraction?.warnings || [];
  const missingFields = extracted?.extraction?.missing_fields || [];
  const emptyRecord = extracted?.extraction?.empty_record === true;

  if (emptyRecord) {
    validationErrors.push('empty_record');
    reviewReasons.push('Record is mostly empty and cannot be processed automatically.');
  }

  if (!email) {
    validationWarnings.push('missing_email');
    reviewReasons.push('Email is missing.');
  } else if (!isValidEmail(email)) {
    validationErrors.push('invalid_email_format');
    reviewReasons.push('Email format is invalid.');
  }

  const suggestedEmailDomainCorrection = hasLikelyEmailTypo(emailDomain);

  if (suggestedEmailDomainCorrection) {
    validationWarnings.push('possible_email_domain_typo');
    reviewReasons.push(`Email domain may be typo: ${emailDomain} → ${suggestedEmailDomainCorrection}.`);
  }

  if (!companyName && !inferredDomain) {
    validationErrors.push('missing_company_identity');
    reviewReasons.push('No company name or usable company domain found.');
  }

  if (!companyName && inferredDomain) {
    validationWarnings.push('missing_company_name_but_domain_available');
    reviewReasons.push('Company name is missing, but email/domain may identify the organisation.');
  }

  if (extractionWarnings.includes('generic_email_domain') && !companyName) {
    validationErrors.push('generic_email_without_company');
    reviewReasons.push('Generic email domain and no company name. Cannot identify company confidently.');
  }

  if (extractionWarnings.includes('possible_swapped_person_and_company_fields')) {
    validationWarnings.push('fields_were_probably_swapped');
    reviewReasons.push('Person and company fields were probably swapped and corrected during extraction.');
  }

  if (!timestamp) {
    validationWarnings.push('missing_timestamp');
    reviewReasons.push('Timestamp is missing.');
  } else if (!isValidTimestamp(timestamp)) {
    validationWarnings.push('invalid_timestamp');
    reviewReasons.push('Timestamp is not parseable.');
  }

  if (!country) {
    validationWarnings.push('missing_country');
    reviewReasons.push('Country is missing.');
  }

  if (!message) {
    validationWarnings.push('missing_message');
    reviewReasons.push('Message is missing.');
  }

  if (confidence === 'low') {
    validationWarnings.push('low_extraction_confidence');
    reviewReasons.push('Extraction confidence is low.');
  }

  const usableForHumanReview = isRecordUsableForHumanReview(extracted);

  let validationStatus = 'valid';

  if (validationErrors.length > 0) {
    validationStatus = usableForHumanReview ? 'needs_review' : 'rejected';
  } else if (validationWarnings.length > 0) {
    validationStatus = 'valid_with_warnings';
  }

  return {
    json: {
      ...lead,

      validation: {
        status: validationStatus,
        errors: validationErrors,
        warnings: validationWarnings,
        review_reasons: [...new Set(reviewReasons)],
        missing_fields: missingFields,
        suggested_email_domain_correction: suggestedEmailDomainCorrection,
        usable_for_human_review: usableForHumanReview,
        checked_at: new Date().toISOString()
      }
    }
  };
});

/**
 * 05A - Mock Enrichment API
 *
 * Purpose:
 * - Simulates a third-party company enrichment API.
 * - Only enriches leads that are:
 *   1. not rejected by validation
 *   2. dedup.status === "new"
 *
 * Why:
 * - Demonstrates cost control.
 * - Avoids enriching duplicates or uncertain duplicate leads before human review.
 * - Keeps auditability by preserving original input and adding enrichment metadata.
 * - Never invents company data when no safe domain is available.
 */

