      company_size: "201-500",
      estimated_employee_count: 300,
      website: "https://different-company.example"
    },
    qualification_signals: {
      project_developer: false,
      renewable_energy_focus: false,
      likely_b2b_customer: false,
      grid_or_utility_relevance: "low",
      market_fit_notes: [
        "Intentional mismatched mock result for enrichment validation testing"
      ]
    },
    contacts: {
      decision_maker_available: true,
      decision_maker_name: "Vendor Returned Name",
      decision_maker_title: "Head of Sales"
    },
    confidence: "low"
  }
};

function deepClone(value) {
  return JSON.parse(JSON.stringify(value));
}

function cleanString(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function normalizeDomain(value) {
  let domain = cleanString(value).toLowerCase();

  domain = domain
    .replace(/^https?:\/\//, "")
    .replace(/^www\./, "")
    .split("/")[0]
    .split("?")[0]
    .split("#")[0];

  return domain;
}

function getEmailDomain(email) {
  const cleanEmail = cleanString(email).toLowerCase();
  if (!cleanEmail.includes("@")) return "";

  return normalizeDomain(cleanEmail.split("@").pop());
}

function isGenericEmailDomain(domain) {
  const genericDomains = new Set([
    "gmail.com",
    "googlemail.com",
    "outlook.com",
    "hotmail.com",
    "live.com",
    "icloud.com",
    "yahoo.com",
    "proton.me",
    "protonmail.com",
    "aol.com",
    "gmx.com",
    "gmx.de",
    "web.de"
  ]);

  return genericDomains.has(normalizeDomain(domain));
}

function getBestCompanyDomain(lead) {
  const company = lead.extracted?.company || {};
  const person = lead.extracted?.person || {};

  const candidates = [
    company.domain,
    company.inferred_domain,
    company.website,
    getEmailDomain(person.email)
  ];

  for (const candidate of candidates) {
    const domain = normalizeDomain(candidate);

    if (!domain) continue;
    if (isGenericEmailDomain(domain)) continue;

    return domain;
  }

  return "";
}

function buildSkippedEnrichment(reason, extra = {}) {
  return {
    status: "skipped",
    checked: false,
    provider: "mock_enrichment_api",
    reason,
    http_status_simulated: null,
    matched_domain: null,
    confidence: "none",
    data: null,
    warnings: [],
    audit: {
      cost_control_applied: true,
      live_api_used: false,
      mock_data_used: false,
      ...extra
    }
  };
}

function buildUnknownEnrichment(reason, domain) {
  return {
    status: "not_found",
    checked: true,
    provider: "mock_enrichment_api",
    reason,
    http_status_simulated: 200,
    matched_domain: domain || null,
    confidence: "unknown",
    data: {
      company: {
        legal_name: "unknown",
        normalized_name: "unknown",
        domain: domain || "unknown",
        country: "unknown",
        region: "unknown",
        industry: "unknown",
        sub_industry: "unknown",
        company_size: "unknown",
        estimated_employee_count: "unknown",
        website: "unknown"
      },
      qualification_signals: {
        project_developer: "unknown",
        renewable_energy_focus: "unknown",
        likely_b2b_customer: "unknown",
        grid_or_utility_relevance: "unknown",
        market_fit_notes: []
      },
      contacts: {
        decision_maker_available: false,
        decision_maker_name: "unknown",
        decision_maker_title: "unknown"
      }
    },
    warnings: ["no_mock_enrichment_record_found"],
    audit: {
      cost_control_applied: true,
      live_api_used: false,
      mock_data_used: false,
      unknown_fields_preserved_as_unknown: true
    }
  };
}

return items.map((item) => {
  const lead = item.json;

  const validationStatus = lead.validation?.status || "unknown";
  const dedupStatus = lead.dedup?.status || "unknown";

  /**
   * Rule 1:
   * Never enrich rejected records.
   */
  if (validationStatus === "rejected") {
    return {
      json: {
        ...lead,
        enrichment: buildSkippedEnrichment("validation_status_rejected", {
          validation_status: validationStatus,
          dedup_status: dedupStatus
        })
      }
    };
  }

  /**
   * Rule 2:
   * Only enrich new leads.
   */
  if (dedupStatus !== "new") {
    return {
      json: {
        ...lead,
        enrichment: buildSkippedEnrichment("dedup_status_not_new", {
          validation_status: validationStatus,
          dedup_status: dedupStatus
        })
      }
    };
  }

  const domain = getBestCompanyDomain(lead);

  /**
   * Rule 3:
   * If there is no safe company domain, do not invent data.
   */
  if (!domain) {
    return {
      json: {
        ...lead,
        enrichment: buildUnknownEnrichment("no_safe_company_domain_available", null)
      }
    };
  }

  const mockRecord = MOCK_ENRICHMENT_DB[domain];

  /**
   * Rule 4:
   * Unknown domains return a clean empty enrichment payload.
   */
  if (!mockRecord) {
    return {
      json: {
        ...lead,
        enrichment: buildUnknownEnrichment("domain_not_found_in_mock_database", domain)
      }
    };
  }

  /**
   * Rule 5:
   * Known domains return mock enrichment data.
   */
  return {
    json: {
      ...lead,
      enrichment: {
        status: "enriched",
        checked: true,
        provider: "mock_enrichment_api",
        reason: "mock_domain_match",
        http_status_simulated: 200,
        matched_domain: domain,
        confidence: mockRecord.confidence || "unknown",
        data: deepClone(mockRecord),
        warnings: domain === "badvendor-match.test"
          ? ["mock_vendor_returned_possible_mismatched_company"]
          : [],
        audit: {
          cost_control_applied: true,
          live_api_used: false,
          mock_data_used: true,
          unknown_fields_preserved_as_unknown: true
        }
      }
    }
  };
});

/**
 * 06A - Validate Enrichment Response
 *
 * Purpose:
 * - Checks whether the enrichment result is usable before scoring.
 * - Does not drop any records.
 * - Adds an enrichment_validation object for auditability.
 *
 * Why:
 * - A vendor/API can return HTTP 200 but still provide bad, mismatched, or low-confidence data.
 * - Scoring should not blindly trust enrichment output.
 */

function cleanString(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function normalizeText(value) {
  return cleanString(value)
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/ä/g, "ae")
    .replace(/ö/g, "oe")
    .replace(/ü/g, "ue")
    .replace(/ß/g, "ss")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizeDomain(value) {
  let domain = cleanString(value).toLowerCase();

  domain = domain
    .replace(/^https?:\/\//, "")
    .replace(/^www\./, "")
    .split("/")[0]
    .split("?")[0]
    .split("#")[0];

  return domain;
}

function tokenOverlapScore(a, b) {
  const tokensA = normalizeText(a).split(" ").filter(Boolean);
  const tokensB = normalizeText(b).split(" ").filter(Boolean);

  if (tokensA.length === 0 || tokensB.length === 0) return 0;

  const setA = new Set(tokensA);
  const setB = new Set(tokensB);

  let overlap = 0;

  for (const token of setA) {
    if (setB.has(token)) overlap++;
  }

  return overlap / Math.max(setA.size, setB.size);
}

function isUnknown(value) {
  const clean = cleanString(value).toLowerCase();
  return clean === "" || clean === "unknown" || clean === "null" || clean === "undefined";
}

function buildSkippedValidation(reason) {
  return {
    status: "skipped",
    usable_for_scoring: false,
    confidence: "none",
    reason,
    errors: [],
    warnings: [],
    review_reasons: [],
    checks: {
      enrichment_present: false,
      enrichment_was_checked: false,
      domain_match: null,
      company_name_match: null,
      has_useful_company_data: false,
      has_useful_qualification_signals: false,
      suspicious_vendor_response: false
    },
    checked_at: new Date().toISOString()
  };
}

return items.map((item) => {
  const lead = item.json;

  const enrichment = lead.enrichment || {};
  const extractedCompany = lead.extracted?.company || {};

  const errors = [];
  const warnings = [];
  const reviewReasons = [];

  const checks = {
    enrichment_present: !!lead.enrichment,
    enrichment_was_checked: enrichment.checked === true,
    domain_match: null,
    company_name_match: null,
    has_useful_company_data: false,
    has_useful_qualification_signals: false,
    suspicious_vendor_response: false
  };

  /**
   * Case 1:
   * Enrichment was intentionally skipped.
   * This is not an error. It means this record should not use enrichment for scoring.
   */
  if (enrichment.status === "skipped") {
    return {
      json: {
        ...lead,
        enrichment_validation: buildSkippedValidation(enrichment.reason || "enrichment_skipped")
      }
    };
  }

  /**
   * Case 2:
   * No enrichment object exists.
   */
  if (!lead.enrichment) {
    errors.push("missing_enrichment_object");
    reviewReasons.push("No enrichment object found on the lead.");

    return {
      json: {
        ...lead,
        enrichment_validation: {
          status: "invalid",
          usable_for_scoring: false,
          confidence: "none",
          reason: "missing_enrichment_object",
          errors,
          warnings,
          review_reasons: reviewReasons,
          checks,
          checked_at: new Date().toISOString()
        }
      }
    };
  }

  /**
   * Case 3:
   * Enrichment returned no data.
   * This is acceptable, but not useful for enrichment-based scoring.
   */
  if (enrichment.status === "not_found") {
    warnings.push("enrichment_not_found");
    reviewReasons.push("Mock enrichment provider returned no usable company data.");

    return {
      json: {
        ...lead,
        enrichment_validation: {
          status: "no_data",
          usable_for_scoring: false,
          confidence: "unknown",
          reason: enrichment.reason || "enrichment_not_found",
          errors,
          warnings,
          review_reasons: reviewReasons,
          checks: {
            ...checks,
            enrichment_present: true,
            enrichment_was_checked: enrichment.checked === true
          },
          checked_at: new Date().toISOString()
        }
      }
    };
  }

  /**
   * Case 4:
   * Unexpected enrichment status.
   */
  if (enrichment.status !== "enriched") {
    errors.push("unexpected_enrichment_status");
    reviewReasons.push(`Unexpected enrichment status received: ${enrichment.status || "missing"}.`);

    return {
      json: {
        ...lead,
        enrichment_validation: {
          status: "invalid",
          usable_for_scoring: false,
          confidence: "none",
          reason: "unexpected_enrichment_status",
          errors,
          warnings,
          review_reasons: reviewReasons,
          checks,
          checked_at: new Date().toISOString()
        }
      }
    };
  }

  const enrichedCompany = enrichment.data?.company || {};
  const enrichedSignals = enrichment.data?.qualification_signals || {};

  const inputDomain = normalizeDomain(
    extractedCompany.inferred_domain ||
    extractedCompany.usable_email_domain ||
    extractedCompany.email_domain ||
    extractedCompany.domain_from_company_field
  );

  const enrichedDomain = normalizeDomain(enrichedCompany.domain);

  const inputCompanyName = extractedCompany.raw_name || extractedCompany.normalized_name || "";
  const enrichedCompanyName = enrichedCompany.legal_name || enrichedCompany.normalized_name || "";

  /**
   * Check 1:
   * Domain consistency.
   */
  if (inputDomain && enrichedDomain) {
    checks.domain_match = inputDomain === enrichedDomain;

    if (!checks.domain_match) {
      errors.push("enrichment_domain_mismatch");
      reviewReasons.push(`Input domain ${inputDomain} does not match enriched domain ${enrichedDomain}.`);
    }
  } else {
    warnings.push("domain_comparison_not_possible");
    reviewReasons.push("Could not compare input domain and enriched domain.");
  }

  /**
   * Check 2:
   * Company name consistency.
   */
  const companyNameScore = tokenOverlapScore(inputCompanyName, enrichedCompanyName);
  checks.company_name_match = companyNameScore >= 0.4;

  if (!checks.company_name_match) {
    warnings.push("company_name_low_similarity");
    reviewReasons.push(`Input company name and enriched company name have low similarity. Score: ${companyNameScore.toFixed(2)}.`);
  }

  /**
   * Check 3:
   * Useful company data exists.
   */
  const usefulCompanyFields = [
    enrichedCompany.legal_name,
    enrichedCompany.normalized_name,
    enrichedCompany.country,
    enrichedCompany.region,
    enrichedCompany.industry,
    enrichedCompany.sub_industry,
    enrichedCompany.company_size,
    enrichedCompany.website
  ].filter((value) => !isUnknown(value));

  checks.has_useful_company_data = usefulCompanyFields.length >= 4;

  if (!checks.has_useful_company_data) {
    warnings.push("limited_company_enrichment_data");
    reviewReasons.push("Enriched company data has too many unknown fields.");
  }

  /**
   * Check 4:
   * Useful qualification signals exist.
   */
  const usefulSignalFields = [
    enrichedSignals.project_developer,
    enrichedSignals.renewable_energy_focus,
    enrichedSignals.likely_b2b_customer,
    enrichedSignals.grid_or_utility_relevance
  ].filter((value) => !isUnknown(value));

  const marketFitNotes = Array.isArray(enrichedSignals.market_fit_notes)
    ? enrichedSignals.market_fit_notes
    : [];

  checks.has_useful_qualification_signals =
    usefulSignalFields.length >= 3 || marketFitNotes.length > 0;

  if (!checks.has_useful_qualification_signals) {
    warnings.push("limited_qualification_signals");
    reviewReasons.push("Enrichment does not contain enough qualification signals.");
  }

  /**
   * Check 5:
   * Suspicious vendor response.
   */
  if (Array.isArray(enrichment.warnings) && enrichment.warnings.length > 0) {
    checks.suspicious_vendor_response = true;
    warnings.push(...enrichment.warnings);
    reviewReasons.push("Enrichment provider returned warning flags.");
  }

  let status = "valid";
  let usableForScoring = true;
  let confidence = enrichment.confidence || "unknown";
  let reason = "enrichment_response_validated";

  if (errors.length > 0) {
    status = "invalid";
    usableForScoring = false;
    confidence = "low";
    reason = "enrichment_response_failed_validation";
  } else if (warnings.length > 0) {
    status = "valid_with_warnings";
    usableForScoring = true;
    reason = "enrichment_response_validated_with_warnings";
  }

  return {
    json: {
      ...lead,
      enrichment_validation: {
        status,
        usable_for_scoring: usableForScoring,
        confidence,
        reason,
        errors,
        warnings,
        review_reasons: reviewReasons,
        checks,
        checked_at: new Date().toISOString()
      }
    }
  };
});

/**
 * 07A - Score Lead
 *
 * Purpose:
 * - Scores each lead using transparent, auditable rules.
 * - Uses raw lead information for all usable leads.
 * - Uses enrichment data only when enrichment_validation.usable_for_scoring === true.
 * - Does not route yet.
 * - Does not drop any records.
 *
 * Portfolio version:
 * - Primary market: Malaysia
 * - Secondary market: Southeast Asia
 * - Generic B2B renewable / energy / infrastructure scoring
 */

function cleanString(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function lower(value) {
  return cleanString(value).toLowerCase();
}

function normalizeText(value) {
  return cleanString(value)
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function includesAny(text, keywords) {
  const normalized = normalizeText(text);
  return keywords.some((keyword) => normalized.includes(normalizeText(keyword)));
}

function addScore(breakdown, category, points, reason) {
  if (!breakdown[category]) {
    breakdown[category] = {
      points: 0,
      reasons: []
    };
  }

  breakdown[category].points += points;

  if (reason) {
    breakdown[category].reasons.push(reason);
  }
}

function sumBreakdown(breakdown) {
  return Object.values(breakdown).reduce((total, category) => {
    return total + Number(category.points || 0);
  }, 0);
}

function clampScore(score) {
  return Math.max(0, Math.min(100, score));
}

function getTier(score) {
  if (score >= 80) return "A";
  if (score >= 60) return "B";
  if (score >= 40) return "C";
  return "D";
}

function getPriority(score) {
  if (score >= 80) return "high";
  if (score >= 60) return "medium";
  if (score >= 40) return "low";
  return "very_low";
}

function getRawText(lead) {
  const context = lead.extracted?.lead_context || {};

  return [
    lead.interest,
    lead.message,
    context.interest,
    context.message,
    lead.company_name,
    lead.extracted?.company?.raw_name,
    lead.extracted?.company?.normalized_name
  ].filter(Boolean).join(" ");
}

function getClientScoreFromTier(tier, scoreStatus = "") {
  if (tier === "A") return 5;
  if (tier === "B") return 4;
  if (tier === "C") return 3;
  if (tier === "D") return 2;

  if (
    tier === "blocked" ||
    scoreStatus === "not_scored" ||
    scoreStatus === "not_sales_ready"
  ) {
    return 1;
  }

  return 1;
}

function getClientScoreRationale(clientScore, tier, scoreStatus, reason) {
  if (clientScore === 5) {
    return "Client score 5 because this is a Tier A lead with strong fit and high sales priority.";
  }

  if (clientScore === 4) {
    return "Client score 4 because this is a Tier B lead with good fit but lower urgency or confidence than Tier A.";
  }

  if (clientScore === 3) {
    return "Client score 3 because this is a Tier C lead with moderate fit and should be treated as lower-priority or nurture.";
  }

  if (clientScore === 2) {
    return "Client score 2 because this is a Tier D lead with weak fit or significant data-quality concerns.";
  }

  return `Client score 1 because this lead is not sales-ready due to ${reason || scoreStatus || "rejection, duplication, or disqualification"}.`;
}

function hasUsefulCompanyIdentity(lead) {
  const company = lead.extracted?.company || {};
  return Boolean(
    cleanString(company.raw_name) ||
    cleanString(company.inferred_domain) ||
    cleanString(company.usable_email_domain)
  );
}

function isSecondaryMarketCountry(country) {
  const normalized = normalizeText(country);

  const secondaryMarkets = new Set([
    "singapore",
    "indonesia",
    "thailand",
    "vietnam",
    "philippines",
    "brunei",
    "cambodia",
    "laos",
    "myanmar"
  ]);

  return secondaryMarkets.has(normalized);
}

function isPrimaryMarket(country) {
  const normalized = normalizeText(country);
  return normalized === "malaysia";
}

function getLeadScoreStatus(lead) {
  const validationStatus = lead.validation?.status || "";
  const dedupStatus = lead.dedup?.status || "";

  if (validationStatus === "rejected") {
    return {
      status: "not_scored",
      eligible_for_sales_routing: false,
      reason: "validation_rejected"
    };
  }

  if (dedupStatus === "duplicate") {
    return {
      status: "not_sales_ready",
      eligible_for_sales_routing: false,
      reason: "duplicate_existing_account"
    };
  }

  if (dedupStatus === "possible_duplicate") {
    return {
      status: "not_sales_ready",
      eligible_for_sales_routing: false,
      reason: "possible_duplicate_requires_human_review"
    };
  }

  if (dedupStatus === "skipped") {
    return {
      status: "not_scored",
      eligible_for_sales_routing: false,
      reason: "dedup_skipped"
    };
  }

  return {
    status: "scored",
    eligible_for_sales_routing: true,
    reason: "lead_scored"
  };
}

return items.map((item) => {
  const lead = item.json;

  const scoreStatus = getLeadScoreStatus(lead);

  const breakdown = {};
  const flags = [];
  const reviewReasons = [];

  const context = lead.extracted?.lead_context || {};
  const company = lead.extracted?.company || {};
  const person = lead.extracted?.person || {};
  const rawText = getRawText(lead);

  const validationStatus = lead.validation?.status || "";
  const enrichmentValidation = lead.enrichment_validation || {};
  const enrichment = lead.enrichment || {};
  const enrichedData = enrichment.data || {};
  const enrichedCompany = enrichedData.company || {};
  const enrichedSignals = enrichedData.qualification_signals || {};

  const canUseEnrichment = enrichmentValidation.usable_for_scoring === true;

  /**
   * Rejected, duplicate, or possible duplicate leads are not sales-ready.
   */
  if (scoreStatus.status !== "scored") {
    return {
      json: {
        ...lead,
        lead_score: {
          status: scoreStatus.status,
          eligible_for_sales_routing: scoreStatus.eligible_for_sales_routing,
          reason: scoreStatus.reason,
          total_score: 0,
          tier: "blocked",
          client_score_1_to_5: 1,
          score_rationale: getClientScoreRationale(
            1,
            "blocked",
            scoreStatus.status,
            scoreStatus.reason
          ),
          priority: "blocked",
          confidence: "none",
          breakdown: {},
          flags,
          review_reasons: [
            scoreStatus.reason
          ],
          scoring_inputs: {
            used_raw_lead_data: true,
            used_enrichment_data: false,
            enrichment_validation_status: enrichmentValidation.status || "",
            validation_status: validationStatus,
            dedup_status: lead.dedup?.status || ""
          },
          scored_at: new Date().toISOString()
        }
      }
    };
  }

  /**
   * 1. Validation quality: max 15
   */
  if (validationStatus === "valid") {
    addScore(breakdown, "validation_quality", 15, "Lead passed validation.");
  } else if (validationStatus === "valid_with_warnings") {
    addScore(breakdown, "validation_quality", 10, "Lead passed validation with warnings.");
    flags.push("validation_warnings_present");
  } else if (validationStatus === "needs_review") {
    addScore(breakdown, "validation_quality", 5, "Lead is usable but needs human review.");
    flags.push("needs_review");
    reviewReasons.push("Validation status requires human review.");
  }

  if (hasUsefulCompanyIdentity(lead)) {
    addScore(breakdown, "company_identity", 10, "Company identity is available.");
  } else {
    flags.push("missing_company_identity");
    reviewReasons.push("Company identity is weak or missing.");
  }

  if (cleanString(person.email)) {
    addScore(breakdown, "contactability", 5, "Email is available.");
  }

  if (cleanString(person.phone)) {
    addScore(breakdown, "contactability", 5, "Phone number is available.");
  } else {
    flags.push("missing_phone");
  }

  /**
   * 2. Geography fit: max 20
   */
  const country = context.country || lead.country || "";

  if (isPrimaryMarket(country)) {
    addScore(breakdown, "geography_fit", 20, "Lead is in Malaysia, the primary market.");
  } else if (isSecondaryMarketCountry(country)) {
    addScore(breakdown, "geography_fit", 12, "Lead is in Southeast Asia, but outside the primary Malaysia market.");
    flags.push("outside_primary_market");
  } else if (cleanString(country)) {
    addScore(breakdown, "geography_fit", 2, "Lead is outside the target Southeast Asia market.");
    flags.push("outside_target_market");
    reviewReasons.push("Country is outside the main target market.");
  } else {
    flags.push("missing_country");
    reviewReasons.push("Country is missing.");
  }

  /**
   * 3. Project / intent fit from raw lead text: max 25
   */
  if (includesAny(rawText, [
    "solar",
    "pv",
    "photovoltaic",
    "rooftop",
    "solar farm",
    "storage",
    "battery",
    "wind",
    "renewable",
    "energy efficiency",
    "grid integration"
  ])) {
    addScore(breakdown, "project_fit", 10, "Lead mentions renewable-energy or energy-infrastructure project interest.");
  }

  if (includesAny(rawText, [
    "project",
    "development",
    "co-develop",
    "partnership",
    "partner",
    "cooperation",
    "tender",
    "procurement",
    "supply agreement",
    "integration"
  ])) {
    addScore(breakdown, "project_fit", 8, "Lead message suggests a partnership, procurement, integration, or development opportunity.");
  }

  if (includesAny(rawText, [
    "mw",
    "mwh",
    "kw",
    "500kw",
    "3mw",
    "million",
    "budget",
    "industrial",
    "factory",
    "warehouse",
    "logistics",
    "facility",
    "municipal",
    "grid"
  ])) {
    addScore(breakdown, "project_fit", 7, "Lead includes project size, budget, asset, or infrastructure signal.");
  }

  /**
   * 4. Company type / market fit from raw text: max 15
   */
  if (includesAny(rawText, [
    "utility",
    "energy",
    "municipal",
    "grid",
    "procurement",
    "industrial",
    "factory",
    "warehouse",
    "logistics",
    "solar",
    "wind",
    "renewable",
    "battery",
    "storage",
    "infrastructure",
    "manufacturing",
    "commercial"
  ])) {
    addScore(breakdown, "company_fit", 10, "Company or message appears relevant to energy, infrastructure, industrial, commercial, or renewable sector.");
  }

  if (includesAny(rawText, [
    "supplier",
    "equipment supplier",
    "manufacturer only",
    "vendor only",
    "we manufacture",
    "offer supply pricing"
  ])) {
    addScore(breakdown, "company_fit", -8, "Lead appears more like a supplier/vendor than a project opportunity.");
    flags.push("supplier_or_vendor_style_lead");
    reviewReasons.push("Lead may be a supplier rather than a buyer or project partner.");
  }

  /**
   * 5. Trusted enrichment bonus: max 20
   */
  if (canUseEnrichment) {
    addScore(breakdown, "trusted_enrichment", 5, "Enrichment response passed validation.");

    if (enrichedSignals.renewable_energy_focus === true) {
      addScore(breakdown, "trusted_enrichment", 5, "Enrichment confirms renewable-energy focus.");
    }

    if (enrichedSignals.likely_b2b_customer === true) {
      addScore(breakdown, "trusted_enrichment", 5, "Enrichment suggests likely B2B customer or partner fit.");
    }

    if (
      enrichedSignals.grid_or_utility_relevance === "high" ||
      enrichedCompany.industry === "energy_infrastructure" ||
      enrichedCompany.industry === "municipal_energy" ||
      enrichedCompany.sub_industry === "battery_storage_and_grid_integration" ||
      enrichedCompany.sub_industry === "public_sector_energy_efficiency"
    ) {
      addScore(breakdown, "trusted_enrichment", 5, "Enrichment suggests high grid, municipal, or energy-infrastructure relevance.");
    }
  } else {
    flags.push("no_trusted_enrichment_used");
  }

  /**
   * 6. Penalties / caution signals
   */
  if (Array.isArray(lead.validation?.warnings) && lead.validation.warnings.includes("possible_email_domain_typo")) {
    addScore(breakdown, "penalties", -8, "Possible email domain typo.");
    flags.push("possible_email_domain_typo");
    reviewReasons.push("Email domain may need correction before outreach.");
  }

  if (validationStatus === "needs_review") {
    addScore(breakdown, "penalties", -10, "Lead requires manual review before confident routing.");
  }

  if (company.is_generic_email_domain === true && !cleanString(company.raw_name)) {
    addScore(breakdown, "penalties", -10, "Generic email domain without company name.");
    flags.push("generic_email_without_company");
  }

  const rawScore = sumBreakdown(breakdown);
  const totalScore = clampScore(rawScore);

  const tier = getTier(totalScore);
  const priority = getPriority(totalScore);
  const clientScore = getClientScoreFromTier(tier, "scored");
  const scoreRationale = getClientScoreRationale(
    clientScore,
    tier,
    "scored",
    "lead_scored"
  );

  let confidence = "medium";

  if (canUseEnrichment && validationStatus === "valid") {
    confidence = "high";
  } else if (!canUseEnrichment || validationStatus !== "valid") {
    confidence = "medium";
  }

  if (validationStatus === "needs_review") {
    confidence = "low";
  }

  return {
    json: {
      ...lead,
      lead_score: {
        status: "scored",
        eligible_for_sales_routing: true,
        reason: "lead_scored",
        total_score: totalScore,
        tier,
        client_score_1_to_5: clientScore,
        score_rationale: scoreRationale,
        priority,
        confidence,
        breakdown,
        flags: [...new Set(flags)],
        review_reasons: [...new Set(reviewReasons)],
        scoring_inputs: {
          used_raw_lead_data: true,
          used_enrichment_data: canUseEnrichment,
          enrichment_validation_status: enrichmentValidation.status || "",
          validation_status: validationStatus,
          dedup_status: lead.dedup?.status || ""
        },
        scored_at: new Date().toISOString()
      }
    }
  };
});

/**
 * 08A - Route Lead
 *
 * Purpose:
 * - Converts validation, deduplication, enrichment validation, and lead score into a business route.
 * - Does not write to CRM or files yet.
 * - Does not drop records.
 * - Routes each lead into one of three production-style outcomes:
 *   1. Qualified CRM-ready lead
 *   2. Human review queue
 *   3. Audit / archive log
 *
 * Portfolio version:
 * - Primary market: Malaysia
 * - Secondary market: Southeast Asia
 * - Generic CRM wording instead of client-specific or assessment wording
 */

function cleanString(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function normalizeText(value) {
  return cleanString(value)
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function isPrimaryMarket(country) {
  const normalized = normalizeText(country);
  return normalized === "malaysia";
}

function isSecondaryMarketCountry(country) {
  const normalized = normalizeText(country);

  const secondaryMarkets = new Set([
    "singapore",
    "indonesia",
    "thailand",
    "vietnam",
    "philippines",
    "brunei",
    "cambodia",
    "laos",
    "myanmar"
  ]);

  return secondaryMarkets.has(normalized);
}

function buildRoute({
  route,
  action,
  owner_team,
  priority,
  reason,
  sla_hours,
  should_create_crm_deal,
  should_create_crm_activity,
  should_notify_sales,
  should_log_to_audit,
  review_required,
  route_notes,
  next_step
}) {
  return {
    route,
    action,
    owner_team,
    priority,
    reason,
    sla_hours,
    should_create_crm_deal,
    should_create_crm_activity,
    should_notify_sales,
    should_log_to_audit,
    review_required,
    route_notes: Array.isArray(route_notes) ? route_notes.filter(Boolean) : [],
    next_step,
    routed_at: new Date().toISOString()
  };
}

function hasAnyFlag(flags, targetFlags) {
  if (!Array.isArray(flags)) return false;
  return targetFlags.some(flag => flags.includes(flag));
}

function getCountry(lead) {
  return (
    lead.extracted?.lead_context?.country ||
    lead.country ||
    ""
  );
}

function getScoreValue(lead) {
  const value = Number(lead.lead_score?.total_score);
  return Number.isFinite(value) ? value : 0;
}

function getTier(lead) {
  return cleanString(lead.lead_score?.tier || "");
}

function getPriorityFromScore(totalScore) {
  if (totalScore >= 80) return "high";
  if (totalScore >= 60) return "medium";
  if (totalScore >= 40) return "low";
  return "very_low";
}

return items.map((item) => {
  const lead = item.json || {};

  const validationStatus = cleanString(lead.validation?.status || "unknown");
  const dedupStatus = cleanString(lead.dedup?.status || "unknown");
  const enrichmentValidationStatus = cleanString(lead.enrichment_validation?.status || "unknown");
  const enrichmentUsableForScoring = lead.enrichment_validation?.usable_for_scoring === true;

  const leadScore = lead.lead_score || {};
  const scoreStatus = cleanString(leadScore.status || "unknown");
  const totalScore = getScoreValue(lead);
  const tier = getTier(lead);
  const priority = leadScore.priority || getPriorityFromScore(totalScore);
  const scoreFlags = Array.isArray(leadScore.flags) ? leadScore.flags : [];
  const country = getCountry(lead);

  const routeNotes = [
    `Validation status: ${validationStatus}`,
    `Dedup status: ${dedupStatus}`,
    `Enrichment validation status: ${enrichmentValidationStatus}`,
    `Score status: ${scoreStatus}`,
    `Score: ${totalScore}`,
    `Tier: ${tier || "none"}`,
    `Country: ${country || "unknown"}`
  ];

  /**
   * 1. Rejected or unprocessable records
   */
  if (
    validationStatus === "rejected" ||
    scoreStatus === "not_scored" ||
    leadScore.eligible_for_sales_routing === false
  ) {
    return {
      json: {
        ...lead,
        routing: buildRoute({
          route: "disqualified_audit_log",
          action: "log_only_no_sales_action",
          owner_team: "operations",
          priority: "very_low",
          reason: leadScore.reason || "Lead is rejected, not scored, or not eligible for sales routing.",
          sla_hours: null,
          should_create_crm_deal: false,
          should_create_crm_activity: false,
          should_notify_sales: false,
          should_log_to_audit: true,
          review_required: false,
          route_notes: [
            ...routeNotes,
            ...(lead.validation?.review_reasons || []),
            ...(leadScore.review_reasons || [])
          ],
          next_step: "Keep in audit log for traceability. No sales action required."
        })
      }
    };
  }

  /**
   * 2. Existing CRM duplicate
   */
  if (dedupStatus === "duplicate") {
    return {
      json: {
        ...lead,
        routing: buildRoute({
          route: "existing_crm_record",
          action: "create_crm_activity_only",
          owner_team: "sales_operations",
          priority: "low",
          reason: "Lead matches an existing CRM organization.",
          sla_hours: 48,
          should_create_crm_deal: false,
          should_create_crm_activity: true,
          should_notify_sales: false,
          should_log_to_audit: true,
          review_required: false,
          route_notes: [
            ...routeNotes,
            `Matched company: ${lead.dedup?.matched_company_name || "unknown"}`,
            `Match type: ${lead.dedup?.match_type || "unknown"}`,
            `Match score: ${lead.dedup?.match_score ?? "unknown"}`,
            "Do not create a duplicate CRM deal."
          ],
          next_step: "Attach activity or note to the existing CRM organization."
        })
      }
    };
  }

  /**
   * 3. Possible duplicate / subsidiary / fuzzy match
   */
  if (dedupStatus === "possible_duplicate") {
    return {
      json: {
        ...lead,
        routing: buildRoute({
          route: "manual_duplicate_review",
          action: "manual_entity_resolution_review",
          owner_team: "sales_operations",
          priority: totalScore >= 70 ? "medium" : "low",
          reason: "Lead may match an existing CRM organization but requires human review before merging or creating a new deal.",
          sla_hours: 24,
          should_create_crm_deal: false,
          should_create_crm_activity: false,
          should_notify_sales: false,
          should_log_to_audit: true,
          review_required: true,
          route_notes: [
            ...routeNotes,
            `Matched company: ${lead.dedup?.matched_company_name || "unknown"}`,
            `Match type: ${lead.dedup?.match_type || "unknown"}`,
            `Match score: ${lead.dedup?.match_score ?? "unknown"}`,
            lead.dedup?.reason || ""
          ],
          next_step: "Confirm whether this is the same company, a subsidiary, or a new organization."
        })
      }
    };
  }

  /**
   * 4. Enrichment response failed validation
   */
  if (enrichmentValidationStatus === "invalid") {
    return {
      json: {
        ...lead,
        routing: buildRoute({
          route: "manual_enrichment_review",
          action: "manual_enrichment_validation_review",
          owner_team: "sales_operations",
          priority: totalScore >= 60 ? "medium" : "low",
          reason: "Enrichment response failed validation and should not be trusted without review.",
          sla_hours: 24,
          should_create_crm_deal: false,
          should_create_crm_activity: false,
          should_notify_sales: false,
          should_log_to_audit: true,
          review_required: true,
          route_notes: [
            ...routeNotes,
            ...(lead.enrichment_validation?.review_reasons || []),
            ...(lead.enrichment_validation?.errors || []),
            ...(lead.enrichment_validation?.warnings || [])
          ],
          next_step: "Review enrichment mismatch before deciding whether to create a CRM deal."
        })
      }
    };
  }

  /**
   * 5. Non-target market review
   *
   * A strong lead outside Malaysia may still be interesting,
   * but it should not enter normal Malaysia sales routing directly.
   */
  if (cleanString(country) && !isPrimaryMarket(country)) {
    const isSecondaryMarket = isSecondaryMarketCountry(country);

    if (!isSecondaryMarket) {
      return {
        json: {
          ...lead,
          routing: buildRoute({
            route: "non_target_market_review",
            action: "manual_market_fit_review",
            owner_team: "partnerships",
            priority: totalScore >= 60 ? "medium" : "low",
            reason: "Lead is outside the current target Southeast Asia market.",
            sla_hours: 48,
            should_create_crm_deal: false,
            should_create_crm_activity: false,
            should_notify_sales: false,
            should_log_to_audit: true,
            review_required: true,
            route_notes: [
              ...routeNotes,
              "Do not route to normal Malaysia sales workflow without review."
            ],
            next_step: "Review for partnership, supplier, or future expansion relevance."
          })
        }
      };
    }

    return {
      json: {
        ...lead,
        routing: buildRoute({
          route: "secondary_market_review",
          action: "manual_market_fit_review",
          owner_team: "sales_operations",
          priority: totalScore >= 70 ? "medium" : "low",
          reason: "Lead is in Southeast Asia but outside the primary Malaysia market.",
          sla_hours: 48,
          should_create_crm_deal: false,
          should_create_crm_activity: false,
          should_notify_sales: false,
          should_log_to_audit: true,
          review_required: true,
          route_notes: [
            ...routeNotes,
            "Review before creating a normal Malaysia sales deal."
          ],
          next_step: "Review market ownership and decide whether to create CRM deal or partner handoff."
        })
      }
    };
  }

  /**
   * 6. Needs review or weak identity
   */
  if (
    validationStatus === "needs_review" ||
    hasAnyFlag(scoreFlags, [
      "generic_email_without_company",
      "missing_company_identity",
      "possible_email_domain_typo",
      "low_extraction_confidence"
    ])
  ) {
    return {
      json: {
        ...lead,
        routing: buildRoute({
          route: "manual_review",
          action: "manual_data_quality_review",
          owner_team: "sales_operations",
          priority: totalScore >= 50 ? "medium" : "low",
          reason: "Lead has data quality issues that require review before outreach.",
          sla_hours: 48,
          should_create_crm_deal: false,
          should_create_crm_activity: false,
          should_notify_sales: false,
          should_log_to_audit: true,
          review_required: true,
          route_notes: [
            ...routeNotes,
            ...(lead.validation?.review_reasons || []),
            ...(leadScore.review_reasons || [])
          ],
          next_step: "Fix or confirm company identity before routing to sales."
        })
      }
    };
  }

  /**
   * 7. Supplier / vendor style leads
   */
  if (
    hasAnyFlag(scoreFlags, [
      "supplier_or_vendor_style_lead",
      "equipment_supplier",
      "vendor_outreach",
      "low_buyer_intent"
    ])
  ) {
    return {
      json: {
        ...lead,
        routing: buildRoute({
          route: "supplier_partner_review",
          action: "manual_supplier_or_partner_review",
          owner_team: "partnerships",
          priority: totalScore >= 60 ? "medium" : "low",
          reason: "Lead appears to be a supplier, vendor, or partnership inquiry rather than a direct sales opportunity.",
          sla_hours: 72,
          should_create_crm_deal: false,
          should_create_crm_activity: false,
          should_notify_sales: false,
          should_log_to_audit: true,
          review_required: true,
          route_notes: [
            ...routeNotes,
            ...(leadScore.review_reasons || [])
          ],
          next_step: "Review as a potential supplier, partner, or non-sales opportunity."
        })
      }
    };
  }

  /**
   * 8. Qualified CRM-ready leads
   */
  if (
    leadScore.eligible_for_sales_routing === true &&
    dedupStatus === "new" &&
    ["A", "B"].includes(tier) &&
    totalScore >= 60
  ) {
    return {
      json: {
        ...lead,
        routing: buildRoute({
          route: "qualified_to_crm",
          action: "create_crm_deal_and_activity",
          owner_team: "sales",
          priority: priority || "medium",
          reason: `Lead is qualified for CRM creation as Tier ${tier}.`,
          sla_hours: tier === "A" ? 4 : 24,
          should_create_crm_deal: true,
          should_create_crm_activity: true,
          should_notify_sales: tier === "A",
          should_log_to_audit: true,
          review_required: false,
          route_notes: [
            ...routeNotes,
            enrichmentUsableForScoring
              ? "Validated enrichment data was available for scoring."
              : "Lead was scored without relying on enrichment data.",
            tier === "A"
              ? "High-priority lead. Sales follow-up recommended within 4 hours."
              : "Qualified lead. Sales follow-up recommended within 24 hours."
          ],
          next_step: "Create CRM deal, add activity/note, and assign to sales."
        })
      }
    };
  }

  /**
   * 9. Borderline nurture / review queue
   */
  if (
    tier === "C" ||
    (totalScore >= 40 && totalScore < 60)
  ) {
    return {
      json: {
        ...lead,
        routing: buildRoute({
          route: "nurture_or_review_queue",
          action: "add_to_review_or_nurture_queue",
          owner_team: "marketing",
          priority: "low",
          reason: "Lead has moderate fit but is not strong enough for immediate CRM deal creation.",
          sla_hours: 72,
          should_create_crm_deal: false,
          should_create_crm_activity: false,
          should_notify_sales: false,
          should_log_to_audit: true,
          review_required: true,
          route_notes: [
            ...routeNotes,
            ...(leadScore.review_reasons || [])
          ],
          next_step: "Add to nurture or marketing follow-up list."
        })
      }
    };
  }

  /**
   * 10. Low-quality catch-all
   */
  return {
    json: {
      ...lead,
      routing: buildRoute({
        route: "low_quality_archive",
        action: "archive_no_sales_action",
        owner_team: "marketing",
        priority: "very_low",
        reason: "Lead score is too low for active sales or nurture action.",
        sla_hours: null,
        should_create_crm_deal: false,
        should_create_crm_activity: false,
        should_notify_sales: false,
        should_log_to_audit: true,
        review_required: false,
        route_notes: [
          ...routeNotes,
          ...(leadScore.review_reasons || [])
        ],
        next_step: "Keep in audit log only unless manually reactivated."
      })
    }
  };
});

/**
 * 09A - Prepare CRM and Audit Outputs
 *
 * Purpose:
 * - Prepares clean, business-ready output objects for:
 *   1. Mock CRM deal creation
 *   2. Mock CRM activity/note creation
 *   3. Human review queue
 *   4. Audit log
 *
 * Important:
 * - This node does NOT call a live CRM or Google Sheets.
 * - It only prepares clean payloads.
 * - It does not drop records.
 * - It surfaces client_score_1_to_5 and score_rationale in:
 *   1. lead_summary
 *   2. mock CRM deal custom fields and note
 *   3. human review payload
 *   4. audit log
 */

function cleanString(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function normalizeDomain(value) {
  let domain = cleanString(value).toLowerCase();

  domain = domain
    .replace(/^https?:\/\//, "")
    .replace(/^www\./, "")
    .split("/")[0]
    .split("?")[0]
    .split("#")[0];

  return domain;
}

function getEmailDomain(email) {
  const cleanEmail = cleanString(email).toLowerCase();
  if (!cleanEmail.includes("@")) return "";

  return normalizeDomain(cleanEmail.split("@").pop());
}

function isGenericEmailDomain(domain) {
  const genericDomains = new Set([
    "gmail.com",
    "googlemail.com",
    "outlook.com",
    "hotmail.com",
    "live.com",
    "icloud.com",
    "yahoo.com",
    "proton.me",
    "protonmail.com",
    "aol.com",
    "gmx.com",
    "gmx.de",
    "web.de"
  ]);

  return genericDomains.has(normalizeDomain(domain));
}

function isUnknown(value) {
  const clean = cleanString(value).toLowerCase();
  return clean === "" || clean === "unknown" || clean === "null" || clean === "undefined";
}

function buildCompanyDisplay(lead) {
  const extractedCompany = lead.extracted?.company || {};
  const person = lead.extracted?.person || {};
  const enrichment = lead.enrichment || {};
  const enrichmentValidation = lead.enrichment_validation || {};
  const enrichedCompany = enrichment.data?.company || {};

  const canUseEnrichment = enrichmentValidation.usable_for_scoring === true;

  const enrichedLegalName = cleanString(enrichedCompany.legal_name);
  const enrichedNormalizedName = cleanString(enrichedCompany.normalized_name);
  const rawCompanyName = cleanString(extractedCompany.raw_name);
  const inferredDomain = normalizeDomain(extractedCompany.inferred_domain);
  const usableEmailDomain = normalizeDomain(extractedCompany.usable_email_domain);
  const domainFromCompanyField = normalizeDomain(extractedCompany.domain_from_company_field);
  const emailDomain = normalizeDomain(getEmailDomain(person.email));

  if (canUseEnrichment && !isUnknown(enrichedLegalName)) {
    return {
      company_display_name: enrichedLegalName,
      company_display_source: "trusted_enrichment_legal_name",
      company_name_needs_review: false,
      company_domain: normalizeDomain(enrichedCompany.domain) || inferredDomain || usableEmailDomain || "",
      company_identity_quality: "high"
    };
  }

  if (canUseEnrichment && !isUnknown(enrichedNormalizedName)) {
    return {
      company_display_name: enrichedNormalizedName,
      company_display_source: "trusted_enrichment_normalized_name",
      company_name_needs_review: false,
      company_domain: normalizeDomain(enrichedCompany.domain) || inferredDomain || usableEmailDomain || "",
      company_identity_quality: "high"
    };
  }

  if (!isUnknown(rawCompanyName)) {
    return {
      company_display_name: rawCompanyName,
      company_display_source: "extracted_raw_company_name",
      company_name_needs_review: false,
      company_domain: inferredDomain || usableEmailDomain || domainFromCompanyField || "",
      company_identity_quality: "medium"
    };
  }

  if (!isUnknown(inferredDomain)) {
    return {
      company_display_name: inferredDomain,
      company_display_source: "inferred_domain",
      company_name_needs_review: true,
      company_domain: inferredDomain,
      company_identity_quality: "low"
    };
  }

  if (!isUnknown(usableEmailDomain)) {
    return {
      company_display_name: usableEmailDomain,
      company_display_source: "usable_email_domain",
      company_name_needs_review: true,
      company_domain: usableEmailDomain,
      company_identity_quality: "low"
    };
  }

  if (!isUnknown(domainFromCompanyField)) {
    return {
      company_display_name: domainFromCompanyField,
      company_display_source: "domain_from_company_field",
      company_name_needs_review: true,
      company_domain: domainFromCompanyField,
      company_identity_quality: "low"
    };
  }

  if (!isUnknown(emailDomain) && !isGenericEmailDomain(emailDomain)) {
    return {
      company_display_name: emailDomain,
      company_display_source: "non_generic_email_domain",
      company_name_needs_review: true,
      company_domain: emailDomain,
      company_identity_quality: "low"
    };
  }

  return {
    company_display_name: "unknown",
    company_display_source: "unavailable",
    company_name_needs_review: true,
    company_domain: "",
    company_identity_quality: "unknown"
  };
}

function buildContactDisplay(lead) {
  const person = lead.extracted?.person || {};

  return {
    person_full_name: cleanString(person.full_name),
    first_name: cleanString(person.first_name),
    last_name: cleanString(person.last_name),
    email: cleanString(person.email),
    phone: cleanString(person.phone)
  };
}

