/**
 * 10A - Split Output Records
 *
 * Purpose:
 * - Converts each processed lead into separate output records:
 *   1. crm_deal
 *   2. crm_activity
 *   3. human_review
 *   4. audit_log
 *
 * Why:
 * - Later nodes can easily write each output type to a separate file/API.
 * - Keeps audit records for every lead.
 * - Does not call external APIs yet.
 *
 * Portfolio cleanup:
 * - Uses generic mock_crm_* destination names.
 * - Keeps client_score_1_to_5 and score_rationale visible at the split-record level.
 */

function buildOutputRecord({
  sourceLead,
  outputType,
  operation,
  destination,
  payload
}) {
  const summary = sourceLead.output_preparation?.outputs?.lead_summary || {};
  const routing = sourceLead.routing || {};
  const score = sourceLead.lead_score || {};

  return {
    json: {
      output_id: `${sourceLead.intake_id || "unknown"}_${outputType}_${Date.now()}`,
      output_type: outputType,
      operation,
      destination,
      prepared_at: new Date().toISOString(),

      intake_id: sourceLead.intake_id || "",
      source: sourceLead.extracted?.lead_context?.source || sourceLead.source || "",
      company_display_name: summary.company_display_name || "",
      company_domain: summary.company_domain || "",
      person_full_name: summary.person_full_name || "",
      email: summary.email || "",
      phone: summary.phone || "",
      country: summary.country || "",
      language: summary.language || "",

      route: routing.route || "",
      action: routing.action || "",
      owner_team: routing.owner_team || "",
      routing_priority: routing.priority || "",
      review_required: routing.review_required ?? false,

      score_status: score.status || "",
      total_score: score.total_score ?? null,
      tier: score.tier || "",
      client_score_1_to_5: score.client_score_1_to_5 ?? null,
      score_rationale: score.score_rationale || "",
      score_confidence: score.confidence || "",

      validation_status: sourceLead.validation?.status || "",
      dedup_status: sourceLead.dedup?.status || "",
      enrichment_status: sourceLead.enrichment?.status || "",
      enrichment_validation_status: sourceLead.enrichment_validation?.status || "",

      payload
    }
  };
}

const outputItems = [];

for (const item of items) {
  const lead = item.json;
  const outputs = lead.output_preparation?.outputs || {};

  /**
   * 1. CRM deal output
   */
  if (outputs.mock_crm_deal) {
    outputItems.push(
      buildOutputRecord({
        sourceLead: lead,
        outputType: "crm_deal",
        operation: outputs.mock_crm_deal.operation || "create_deal",
        destination: "mock_crm_deals",
        payload: outputs.mock_crm_deal
      })
    );
  }

  /**
   * 2. CRM activity / note output
   */
  if (outputs.mock_crm_activity) {
    outputItems.push(
      buildOutputRecord({
        sourceLead: lead,
        outputType: "crm_activity",
        operation: outputs.mock_crm_activity.operation || "create_activity",
        destination: "mock_crm_activities",
        payload: outputs.mock_crm_activity
      })
    );
  }

  /**
   * 3. Human review queue output
   */
  if (outputs.human_review_queue) {
    outputItems.push(
      buildOutputRecord({
        sourceLead: lead,
        outputType: "human_review",
        operation: outputs.human_review_queue.operation || "add_to_human_review_queue",
        destination: "human_review_queue",
        payload: outputs.human_review_queue
      })
    );
  }

  /**
   * 4. Audit log output
   *
   * Every lead should always produce one audit log record.
   */
  if (outputs.audit_log) {
    outputItems.push(
      buildOutputRecord({
        sourceLead: lead,
        outputType: "audit_log",
        operation: outputs.audit_log.operation || "append_audit_log",
        destination: "audit_log",
        payload: outputs.audit_log
      })
    );
  } else {
    outputItems.push(
      buildOutputRecord({
        sourceLead: lead,
        outputType: "audit_log",
        operation: "append_audit_log_missing_payload",
        destination: "audit_log",
        payload: {
          warning: "Missing audit_log payload from 09A.",
          intake_id: lead.intake_id || "",
          created_at: new Date().toISOString()
        }
      })
    );
  }
}

return outputItems;

/**
 * 11A - Group Output Records by Destination
 *
 * Purpose:
 * - Groups split output records from 10A by destination.
 * - Performs basic count reconciliation.
 * - Keeps one grouped object for 12A to build export files.
 *
 * Portfolio cleanup:
 * - Uses generic mock_crm_deals and mock_crm_activities.
 * - Preserves count checks for production-style auditability.
 */

const grouped = {
  mock_crm_deals: [],
  mock_crm_activities: [],
  human_review_queue: [],
  audit_log: []
};

const unknown_destination_records = [];

for (const item of items) {
  const record = item.json || {};
  const destination = record.destination || "";

  if (destination === "mock_crm_deals") {
    grouped.mock_crm_deals.push(record);
    continue;
  }

  if (destination === "mock_crm_activities") {
    grouped.mock_crm_activities.push(record);
    continue;
  }

  if (destination === "human_review_queue") {
    grouped.human_review_queue.push(record);
    continue;
  }

  if (destination === "audit_log") {
    grouped.audit_log.push(record);
    continue;
  }

  unknown_destination_records.push(record);
}

/**
 * Dynamic count reconciliation.
 *
 * This supports both:
 * - 18-row CSV test runs
 * - 1-lead webhook test runs
 */
const expectedAuditCount = grouped.audit_log.length;

const counts = {
  total_output_records: items.length,
  mock_crm_deals: grouped.mock_crm_deals.length,
  mock_crm_activities: grouped.mock_crm_activities.length,
  human_review_queue: grouped.human_review_queue.length,
  audit_log: grouped.audit_log.length,
  unknown_destination_records: unknown_destination_records.length
};

const quality_checks = {
  has_unknown_destinations: unknown_destination_records.length > 0,
  audit_log_count_matches_input_leads: grouped.audit_log.length === expectedAuditCount,
  has_crm_deals: grouped.mock_crm_deals.length > 0,
  has_crm_activities: grouped.mock_crm_activities.length > 0,
  has_human_review_records: grouped.human_review_queue.length > 0,
  total_count_reconciles:
    grouped.mock_crm_deals.length +
    grouped.mock_crm_activities.length +
    grouped.human_review_queue.length +
    grouped.audit_log.length +
    unknown_destination_records.length === items.length
};

return [
  {
    json: {
      output_grouping_status: quality_checks.total_count_reconciles
        ? "grouped"
        : "count_mismatch",

      generated_at: new Date().toISOString(),

      counts,
      quality_checks,

      grouped_outputs: grouped,
      unknown_destination_records
    }
  }
];

/**
 * 12A - Build Export Files
 *
 * Purpose:
 * - Takes grouped outputs from 11A.
 * - Builds four export-file payloads:
 *   1. mock_crm_deals.json
 *   2. mock_crm_activities.json
 *   3. human_review_queue.json
 *   4. audit_log.json
 *
 * Important:
 * - This node does NOT write files yet.
 * - It prepares file names, file paths, record counts, and JSON content.
 * - It uses generic CRM wording for the portfolio version.
 */

const groupedData = items[0].json;
const grouped = groupedData.grouped_outputs || {};

const EXPORT_BASE_PATH = "/home/node/.n8n-files/sample_outputs";

function buildExportFile({
  outputKey,
  fileName,
  description,
  records
}) {
  const safeRecords = Array.isArray(records) ? records : [];

  const exportObject = {
    file_type: outputKey,
    description,
    generated_at: new Date().toISOString(),
    record_count: safeRecords.length,

    scoring_note: {
      total_score: "Internal 0-100 operational score remains unchanged.",
      tier: "Existing internal tier remains unchanged.",
      client_score_1_to_5: "Client-facing score derived directly from tier: A=5, B=4, C=3, D=2, blocked/rejected/disqualified=1.",
      score_rationale: "One-sentence explanation of the client-facing 1-5 score."
    },

    quality_checks: groupedData.quality_checks || {},
    source_counts: groupedData.counts || {},

    records: safeRecords
  };

  return {
    json: {
      output_key: outputKey,
      file_name: fileName,
      file_path: `${EXPORT_BASE_PATH}/${fileName}`,
      description,
      record_count: safeRecords.length,
      content_type: "application/json",
      file_content: JSON.stringify(exportObject, null, 2)
    }
  };
}

return [
  buildExportFile({
    outputKey: "mock_crm_deals",
    fileName: "mock_crm_deals.json",
    description: "Mock CRM deal creation payloads for qualified new sales leads.",
    records: grouped.mock_crm_deals || []
  }),

  buildExportFile({
    outputKey: "mock_crm_activities",
    fileName: "mock_crm_activities.json",
    description: "Mock CRM activity and note payloads for sales follow-up and duplicate account handling.",
    records: grouped.mock_crm_activities || []
  }),

  buildExportFile({
    outputKey: "human_review_queue",
    fileName: "human_review_queue.json",
    description: "Human review queue records for possible duplicates, weak company identity, non-target market, secondary-market review, or enrichment validation issues.",
    records: grouped.human_review_queue || []
  }),

  buildExportFile({
    outputKey: "audit_log",
    fileName: "audit_log.json",
    description: "Complete audit log for all intake records, including rejected, duplicate, enriched, scored, and routed leads.",
    records: grouped.audit_log || []
  })
];

return items.map((item) => {
  const file = item.json || {};

  const fileContent = file.file_content || "";
  const fileName = file.file_name || "export.json";
  const contentType = file.content_type || "application/json";

  return {
    json: {
      output_key: file.output_key || "",
      file_name: fileName,
      file_path: file.file_path || "",
      description: file.description || "",
      record_count: file.record_count ?? 0,
      content_type: contentType,
      prepared_at: new Date().toISOString()
    },
    binary: {
      data: {
        data: Buffer.from(fileContent, "utf8").toString("base64"),
        mimeType: contentType,
        fileName: fileName
      }
    }
  };
});

