const GENERIC_DOMAINS = [
  'gmail.com',
  'googlemail.com',
  'outlook.com',
  'hotmail.com',
  'yahoo.com',
  'icloud.com',
  'aol.com',
  'proton.me',
  'protonmail.com',
  'gmx.com',
  'gmx.de',
  'web.de',
  'live.com',
  'msn.com'
];

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function normalizeText(value) {
  return clean(value)
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/\b(sdn|bhd|berhad|enterprise|holdings|group|gmbh|ag|se|ltd|llc|inc|corp|corporation|srl|bv|nv|spa|sa|oy|as|ab)\b/g, '')
    .replace(/[^a-z0-9]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeDomain(value) {
  return clean(value)
    .toLowerCase()
    .replace(/^https?:\/\//, '')
    .replace(/^www\./, '')
    .split('/')[0]
    .split('?')[0]
    .split('#')[0]
    .trim();
}

function tokenize(value) {
  return normalizeText(value)
    .split(/\s+/)
    .filter(Boolean);
}

function isGenericDomain(domain) {
  return GENERIC_DOMAINS.includes(normalizeDomain(domain));
}

function jaccardSimilarity(a, b) {
  const setA = new Set(tokenize(a));
  const setB = new Set(tokenize(b));

  if (setA.size === 0 || setB.size === 0) return 0;

  const intersection = [...setA].filter(token => setB.has(token)).length;
  const union = new Set([...setA, ...setB]).size;

  return intersection / union;
}

function levenshteinDistance(a, b) {
  const s = normalizeText(a);
  const t = normalizeText(b);

  const rows = s.length + 1;
  const cols = t.length + 1;
  const matrix = Array.from({ length: rows }, () => Array(cols).fill(0));

  for (let i = 0; i < rows; i++) matrix[i][0] = i;
  for (let j = 0; j < cols; j++) matrix[0][j] = j;

  for (let i = 1; i < rows; i++) {
    for (let j = 1; j < cols; j++) {
      const cost = s[i - 1] === t[j - 1] ? 0 : 1;

      matrix[i][j] = Math.min(
        matrix[i - 1][j] + 1,
        matrix[i][j - 1] + 1,
        matrix[i - 1][j - 1] + cost
      );
    }
  }

  return matrix[s.length][t.length];
}

function levenshteinSimilarity(a, b) {
  const s = normalizeText(a);
  const t = normalizeText(b);

  if (!s || !t) return 0;

  const maxLength = Math.max(s.length, t.length);
  const distance = levenshteinDistance(s, t);

  return 1 - distance / maxLength;
}

function nameSimilarity(a, b) {
  return Math.max(
    jaccardSimilarity(a, b),
    levenshteinSimilarity(a, b)
  );
}

function domainMatchesOrg(org, leadDomain) {
  const domain = normalizeDomain(leadDomain);

  if (!domain || isGenericDomain(domain)) return false;

  const orgDomains = [
    org.domain,
    ...(org.alternative_domains || [])
  ].map(normalizeDomain);

  return orgDomains.includes(domain);
}

function looksLikeSeparateBusinessUnit(leadCompanyName, org) {
  const leadName = normalizeText(leadCompanyName);
  const orgName = normalizeText(org.company_name);
  const orgShortName = normalizeText(org.normalized_name);

  if (!leadName || !orgName) return false;

  const leadTokens = tokenize(leadName);
  const orgTokens = tokenize(orgShortName || orgName);

  if (orgTokens.length === 0) return false;

  const parentToken = orgTokens[0];
  const sharesParent = leadTokens.includes(parentToken);

  const hasExtraUnitWords = leadTokens.length > orgTokens.length;
  const isNotSameName = leadName !== orgShortName && leadName !== orgName;

  return sharesParent && hasExtraUnitWords && isNotSameName;
}

function findDuplicateMatch(lead) {
  const extracted = lead.extracted || {};
  const company = extracted.company || {};

  const leadCompanyName = clean(company.raw_name);
  const leadNormalizedName = clean(company.normalized_name);
  const leadInferredDomain = normalizeDomain(company.inferred_domain);
  const emailDomain = normalizeDomain(company.email_domain);

  const candidateDomain = leadInferredDomain || emailDomain;

  let bestNameMatch = {
    status: 'new',
    confidence: 'high',
    matched_org: null,
    match_type: 'no_match',
    match_score: 0,
    reason: 'No duplicate found against mock CRM organizations.'
  };

  for (const org of MOCK_CRM_ORGS) {
    const domainMatch = domainMatchesOrg(org, candidateDomain);

    if (domainMatch) {
      const possibleSubsidiary =
        normalizeDomain(org.domain) === candidateDomain &&
        looksLikeSeparateBusinessUnit(leadCompanyName, org);

      if (possibleSubsidiary) {
        return {
          status: 'possible_duplicate',
          confidence: 'medium',
          matched_org: org,
          match_type: 'same_parent_domain_possible_subsidiary',
          match_score: 0.75,
          reason: `Lead shares domain ${candidateDomain} with ${org.company_name}, but the company name suggests a separate subsidiary or business unit. Human review required before merging.`
        };
      }

      return {
        status: 'duplicate',
        confidence: 'high',
        matched_org: org,
        match_type: 'domain_match',
        match_score: 1,
        reason: `Lead domain matched existing CRM organization domain: ${candidateDomain}.`
      };
    }

    const orgName = clean(org.normalized_name || org.company_name);
    const score = nameSimilarity(leadNormalizedName || leadCompanyName, orgName);

    if (score > bestNameMatch.match_score) {
      bestNameMatch = {
        status: score >= 0.86 ? 'possible_duplicate' : 'new',
        confidence: score >= 0.86 ? 'medium' : 'high',
        matched_org: score >= 0.86 ? org : null,
        match_type: score >= 0.86 ? 'fuzzy_name_match' : 'no_match',
        match_score: Number(score.toFixed(3)),
        reason: score >= 0.86
          ? `Company name is similar to existing CRM organization: ${org.company_name}.`
          : 'No strong duplicate match found.'
      };
    }
  }

  return bestNameMatch;
}

return items.map((item) => {
  const lead = item.json;
  const validationStatus = clean(lead.validation?.status);

  if (validationStatus === 'rejected') {
    return {
      json: {
        ...lead,
        dedup: {
          status: 'skipped',
          checked: false,
          reason: 'Dedup skipped because validation status is rejected.',
          matched_crm_org_id: '',
          matched_company_name: '',
          match_type: '',
          match_score: 0,
          confidence: 'none',
          checked_at: new Date().toISOString()
        }
      }
    };
  }

  const match = findDuplicateMatch(lead);

  return {
    json: {
      ...lead,
      dedup: {
        status: match.status,
        checked: true,
        reason: match.reason,
        matched_crm_org_id: match.matched_org?.crm_org_id || '',
        matched_company_name: match.matched_org?.company_name || '',
        match_type: match.match_type,
        match_score: match.match_score,
        confidence: match.confidence,
        checked_at: new Date().toISOString(),
        mock_source_note: 'Mock CRM data used for local portfolio testing. Replace with a live CRM organization search API in production.'
      }
    }
  };
});
